from __future__ import annotations

import os
from pathlib import Path

from pydantic import SecretStr
from pydantic_settings import BaseSettings, SettingsConfigDict


class SettingsError(RuntimeError):
    """Raised when repository or environment configuration is invalid."""


def _strip_optional_quotes(value: str) -> str:
    if len(value) >= 2 and value[0] == value[-1] and value[0] in {"'", '"'}:
        return value[1:-1]
    return value


def load_dotenv_file(dotenv_path: Path) -> None:
    if not dotenv_path.exists():
        return

    for line_number, raw_line in enumerate(dotenv_path.read_text().splitlines(), start=1):
        line = raw_line.strip()
        if not line or line.startswith("#"):
            continue

        if "=" not in line:
            raise SettingsError(
                f"Malformed {dotenv_path}: line {line_number} must be KEY=value. "
                "If you pasted the raw Anthropic key, rewrite it as "
                "ANTHROPIC_API_KEY=sk-ant-...."
            )

        key, value = line.split("=", 1)
        key = key.strip()
        value = _strip_optional_quotes(value.strip())
        if not key:
            raise SettingsError(f"Malformed {dotenv_path}: line {line_number} has an empty key.")
        os.environ.setdefault(key, value)


class Settings(BaseSettings):
    model_config = SettingsConfigDict(
        env_prefix="",
        case_sensitive=True,
        extra="ignore",
    )

    anthropic_api_key: SecretStr | None = None
    e2b_api_key: SecretStr | None = None
    anthropic_model_main: str = "claude-sonnet-4-20250514"
    anthropic_model_judge: str = "claude-sonnet-4-20250514"
    gaia_data_path: str | None = None
    results_dir: Path = Path("artifacts/results")
    max_turns: int = 10
    sandbox_timeout_seconds: int = 90
    http_timeout_seconds: int = 20
    max_search_results: int = 5
    max_fetch_chars: int = 18000
    retry_attempts: int = 1
    claude_cli_path: str = "claude"
    working_directory: Path = Path.cwd()

    def require_service_credentials(
        self,
        *,
        require_anthropic: bool = True,
        require_e2b: bool = True,
    ) -> None:
        missing: list[str] = []
        if require_anthropic and self.anthropic_api_key is None:
            missing.append("ANTHROPIC_API_KEY")
        if require_e2b and self.e2b_api_key is None:
            missing.append("E2B_API_KEY")
        if missing:
            joined = ", ".join(missing)
            raise SettingsError(f"Missing required environment variables: {joined}")

    def runtime_env(self) -> dict[str, str]:
        env: dict[str, str] = {}
        if self.anthropic_api_key is not None:
            env["ANTHROPIC_API_KEY"] = self.anthropic_api_key.get_secret_value()
        if self.e2b_api_key is not None:
            env["E2B_API_KEY"] = self.e2b_api_key.get_secret_value()
        return env


def load_settings(dotenv_path: str | Path = ".env") -> Settings:
    load_dotenv_file(Path(dotenv_path))
    return Settings()

from __future__ import annotations

import json
import re
from pathlib import Path
from urllib.parse import parse_qs, urlparse

from datasets import load_dataset

from gaia_bot.models import TaskRecord


def _normalize_answer(value: str | None) -> str:
    if value is None:
        return ""
    collapsed = re.sub(r"\s+", " ", value.strip().casefold())
    collapsed = re.sub(r"[^\w\s\.\-/:]", "", collapsed)
    return collapsed


def score_prediction(predicted: str, expected: str | None) -> float | None:
    if expected is None:
        return None
    return 1.0 if _normalize_answer(predicted) == _normalize_answer(expected) else 0.0


def _task_from_mapping(payload: dict) -> TaskRecord:
    task_id = str(
        payload.get("task_id")
        or payload.get("id")
        or payload.get("Question ID")
        or payload.get("question_id")
    )
    question = payload.get("question") or payload.get("Question") or payload.get("prompt")
    if not task_id or not question:
        raise ValueError(f"Task payload is missing required keys: {payload}")

    expected_answer = (
        payload.get("answer")
        or payload.get("expected_answer")
        or payload.get("final_answer")
    )
    ignored_keys = {
        "task_id",
        "id",
        "Question ID",
        "question_id",
        "question",
        "Question",
        "prompt",
        "answer",
        "expected_answer",
        "final_answer",
    }
    metadata = {
        key: value
        for key, value in payload.items()
        if key not in ignored_keys
    }
    return TaskRecord(
        task_id=task_id,
        question=question,
        expected_answer=expected_answer,
        metadata=metadata,
    )


def _load_json_file(path: Path) -> list[TaskRecord]:
    payload = json.loads(path.read_text())
    if isinstance(payload, list):
        return [_task_from_mapping(item) for item in payload]
    if isinstance(payload, dict) and "tasks" in payload:
        return [_task_from_mapping(item) for item in payload["tasks"]]
    raise ValueError(f"Unsupported JSON dataset structure in {path}")


def _load_jsonl_file(path: Path) -> list[TaskRecord]:
    tasks: list[TaskRecord] = []
    for line in path.read_text().splitlines():
        stripped = line.strip()
        if not stripped:
            continue
        tasks.append(_task_from_mapping(json.loads(stripped)))
    return tasks


def _load_huggingface_dataset(dataset_uri: str) -> list[TaskRecord]:
    parsed = urlparse(dataset_uri)
    dataset_name = f"{parsed.netloc}{parsed.path}"
    params = parse_qs(parsed.query)
    split = params.get("split", ["validation"])[0]
    subset = params.get("subset", [None])[0]
    dataset = load_dataset(dataset_name, subset, split=split)
    return [_task_from_mapping(item) for item in dataset]  # type: ignore[arg-type]


def load_tasks(dataset_path: str | Path) -> list[TaskRecord]:
    if isinstance(dataset_path, Path):
        dataset_path = str(dataset_path)

    if dataset_path.startswith("hf://"):
        return _load_huggingface_dataset(dataset_path)

    path = Path(dataset_path)
    if not path.exists():
        raise FileNotFoundError(f"Dataset path does not exist: {path}")
    if path.suffix == ".jsonl":
        return _load_jsonl_file(path)
    if path.suffix == ".json":
        return _load_json_file(path)
    raise ValueError(f"Unsupported dataset format: {path.suffix}")


def select_subset(
    tasks: list[TaskRecord],
    subset: str | int | None,
    *,
    full: bool = False,
) -> list[TaskRecord]:
    if full or subset is None:
        return tasks
    if isinstance(subset, str) and subset.isdigit():
        subset = int(subset)
    if isinstance(subset, int):
        return tasks[:subset]
    lowered = subset.lower()
    if lowered in {"sample", "smoke"}:
        return tasks[:3]
    return [
        task
        for task in tasks
        if task.metadata.get("split") == subset or task.task_id == subset
    ]

